// HasTenant applies the HasEdge predicate on the "tenant" edge.
func HasTenant() predicate.DiagnosisToolTemplate {
	return predicate.DiagnosisToolTemplate(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, false, TenantTable, TenantColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasTenantWith applies the HasEdge predicate on the "tenant" edge with a given conditions (other predicates).
func HasTenantWith(preds ...predicate.Tenant) predicate.DiagnosisToolTemplate {
	return predicate.DiagnosisToolTemplate(func(s *sql.Selector) {
		step := newTenantStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.DiagnosisToolTemplate) predicate.DiagnosisToolTemplate {
	return predicate.DiagnosisToolTemplate(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.DiagnosisToolTemplate) predicate.DiagnosisToolTemplate {
	return predicate.DiagnosisToolTemplate(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.DiagnosisToolTemplate) predicate.DiagnosisToolTemplate {
	return predicate.DiagnosisToolTemplate(sql.NotPredicates(p))
}
